import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { Category, Source } from '../../core/models';
import { CategoryChipComponent } from '../../shared/category-chip/category-chip.component';
import { EmptyStateComponent } from '../../shared/empty-state/empty-state.component';

@Component({
  selector: 'app-admin-sources',
  standalone: true,
  imports: [CommonModule, FormsModule, CategoryChipComponent, EmptyStateComponent],
  templateUrl: './admin-sources.component.html',
  styleUrl: './admin-sources.component.css',
})
export class AdminSourcesComponent {
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  // --- Backend-provided data (data-contract signals) ------------------------------------
  sources = signal<Source[]>([
    { id: 's1', url: 'https://techcrunch.com/feed/', category: 'Tech', active: true, lastFetchedAt: this.minsAgo(3), lastError: null, articleCount: 128 },
    { id: 's2', url: 'https://www.espn.com/espn/rss/news', category: 'Sports', active: true, lastFetchedAt: this.minsAgo(4), lastError: null, articleCount: 96 },
    { id: 's3', url: 'https://feeds.reuters.com/reuters/worldNews', category: 'World News', active: true, lastFetchedAt: this.minsAgo(2), lastError: null, articleCount: 210 },
    { id: 's4', url: 'https://www.wired.com/feed/rss', category: 'Tech', active: true, lastFetchedAt: this.minsAgo(6), lastError: null, articleCount: 74 },
    { id: 's5', url: 'https://example.com/broken/feed.xml', category: 'Business', active: false, lastFetchedAt: this.minsAgo(52), lastError: 'ECONNREFUSED — host unreachable at last poll', articleCount: 0 },
  ]);

  categories = signal<Category[]>([
    { id: 'c1', name: 'Tech', sourceCount: 2, articleCount: 202 },
    { id: 'c2', name: 'Sports', sourceCount: 1, articleCount: 96 },
    { id: 'c3', name: 'World News', sourceCount: 1, articleCount: 210 },
    { id: 'c4', name: 'Business', sourceCount: 1, articleCount: 0 },
    { id: 'c5', name: 'Science', sourceCount: 0, articleCount: 0 },
  ]);

  // --- Modal state (URL-addressable via ?modal=add-source) ------------------------------
  readonly modalOpen = toSignal(
    this.route.queryParamMap.pipe(map((p) => p.get('modal') === 'add-source')),
    { initialValue: false },
  );

  // Add-source form model
  newUrl = '';
  newCategory = '';
  submitError = '';
  submitting = false;
  refreshing = signal(false);
  toast = signal('');

  readonly hasSources = computed(() => this.sources().length > 0);

  openAddModal(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: 'add-source' },
      queryParamsHandling: 'merge',
    });
  }

  closeModal(): void {
    this.submitError = '';
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: null },
      queryParamsHandling: 'merge',
    });
  }

  addSource(): void {
    this.submitError = '';
    const url = this.newUrl.trim();
    if (!url || !this.newCategory) {
      this.submitError = 'Please enter a feed URL and choose a category.';
      return;
    }
    this.submitting = true;
    // Simulated server-side validation. The real API returns HTTP 422 when a URL is not a
    // reachable / parseable RSS or Atom feed — surface that message here.
    const looksValid = /^https?:\/\/.+/i.test(url) && !/broken|invalid/i.test(url);
    if (!looksValid) {
      this.submitting = false;
      this.submitError = '422 — URL is not a reachable RSS/Atom feed. Source was not saved.';
      return;
    }
    const created: Source = {
      id: 'new-' + this.sources().length,
      url,
      category: this.newCategory,
      active: true,
      lastFetchedAt: null,
      lastError: null,
      articleCount: 0,
    };
    this.sources.update((list) => [created, ...list]);
    this.submitting = false;
    this.newUrl = '';
    this.newCategory = '';
    this.showToast('Source added — initial fetch enqueued.');
    this.closeModal();
  }

  deleteSource(id: string): void {
    this.sources.update((list) => list.filter((s) => s.id !== id));
    this.showToast('Source removed. Existing articles were retained.');
  }

  refreshAll(): void {
    this.refreshing.set(true);
    this.showToast('Refresh queued for all active feeds (202 Accepted).');
    // In the mockup we just clear the flag on the next macrotask.
    setTimeout(() => this.refreshing.set(false), 1200);
  }

  relativeTime(iso: string | null): string {
    if (!iso) return 'never';
    const mins = Math.round((Date.now() - new Date(iso).getTime()) / 60000);
    if (mins < 1) return 'just now';
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.round(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    return `${Math.round(hrs / 24)}d ago`;
  }

  private showToast(msg: string): void {
    this.toast.set(msg);
    setTimeout(() => this.toast.set(''), 2600);
  }

  private minsAgo(m: number): string {
    return new Date(Date.now() - m * 60000).toISOString();
  }
}
